def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        if item > capacity:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.2:
            score = (1 - ratio)**4 + np.sin(ratio * 2 * np.pi) * 0.5
        elif 0.2 <= ratio < 0.4:
            score = np.log1p(ratio * 3) * 2.5 - np.sqrt(ratio) * 0.8 + np.cos(ratio * 7)
        elif 0.4 <= ratio < 0.7:
            score = 1 / (1 + np.exp(-20 * (ratio - 0.55))) + np.cos(ratio * 8) * 0.7
        elif 0.7 <= ratio < 0.85:
            score = np.tanh(15 * (ratio - 0.75)) + 0.3 * np.sin(ratio * 10)
        else:
            score = np.tanh(12 * (ratio - 0.85)) + 0.7
        penalty = 0
        for j in range(1, 8):
            mod_val = ((item * j) % capacity)
            frac = mod_val / (capacity * j)
            if frac < 0.05:
                penalty += frac * 3 + np.cos(frac * 20)
            elif 0.05 <= frac < 0.2:
                penalty += frac * 1.5 + np.sin(frac * 15)
            elif 0.2 <= frac < 0.4:
                penalty += frac / (j ** 0.5)
            else:
                penalty += frac / (j + 1) + 0.1 * np.cos(frac * 5)
        extra_penalty = 0
        for k in range(1, 5):
            if ratio > 0.4 * k:
                extra_penalty += np.exp(-k * ratio) * k * 0.9 + np.sin(k * ratio * 5) * 0.1
            else:
                extra_penalty += np.log1p(k * ratio + 2) / (k + 0.5) + np.cos(k * ratio * 3) * 0.2
        if capacity % 3 == 0:
            priorities[i] = score + penalty * 1.1 + extra_penalty * 0.95
        elif capacity % 5 == 0:
            priorities[i] = score * 0.9 + penalty * 1.3 + extra_penalty
        else:
            priorities[i] = score + penalty * 1.2 + extra_penalty * 0.85
        if priorities[i] < 0:
            priorities[i] = 0
        if priorities[i] > 10:
            priorities[i] = 10 / (1 + np.exp(-(priorities[i]-10)))
    return priorities
